        {(Object.entries(data) as [string, TeamMember[]][]).map(([title, members], index) => (
          <React.Fragment key={title}>
            {renderGroup(title, members)}
            {index < Object.keys(data).length - 1 && <div className="my-16 h-px w-1/4 mx-auto bg-white/5"></div>}
          </React.Fragment>
        ))}
      </div>
    </section>
  );
};

